// Extrae username y password del body. No se logguea el password
// por seguridad.
const body = ($input.first().json.body) || {};
const username = String(body.username || '').trim().toLowerCase();
const password = String(body.password || '');
if (!username || !password) {
  throw new Error('username y password son obligatorios');
}
return [{ json: { username, password } }];

// Verifica la contraseña contra el hash PBKDF2 guardado y construye la
// respuesta. En caso de credenciales inválidas devuelve 401-like con
// success:false. Nunca revela si el usuario existe o no (mismo mensaje
// para ambos casos) — práctica estándar de seguridad.
const crypto = require('crypto');
const { username, password } = $('Preparar Login').first().json;

function verifyPbkdf2(pw, stored) {
  // Formato esperado: pbkdf2$<iterations>$<salt_b64>$<hash_b64>
  if (!stored || typeof stored !== 'string') return false;
  const parts = stored.split('$');
  if (parts.length !== 4 || parts[0] !== 'pbkdf2') return false;
  const iterations = parseInt(parts[1], 10);
  const salt = Buffer.from(parts[2], 'base64');
  const expected = Buffer.from(parts[3], 'base64');
  if (!iterations || salt.length === 0 || expected.length === 0) return false;
  const got = crypto.pbkdf2Sync(pw, salt, iterations, expected.length, 'sha256');
  // Comparación a tiempo constante
  return got.length === expected.length && crypto.timingSafeEqual(got, expected);
}

const rows = ($input.all() || []).map(i => i.json).filter(u => u && u.id);
const user = rows[0] || null;

let ok = false;
if (user && user.password_hash) {
  try { ok = verifyPbkdf2(password, user.password_hash); } catch (_) { ok = false; }
}

if (!ok) {
  return [{ json: { success: false, error: 'Credenciales incorrectas' } }];
}

// Parseo defensivo de permisos (viene como JSONB)
let permisos = [];
try {
  permisos = Array.isArray(user.permisos) ? user.permisos
           : typeof user.permisos === 'string' ? JSON.parse(user.permisos) : [];
} catch (_) { permisos = []; }

// Token simple de sesión: UUID opaco. El cliente lo guarda y lo devuelve
// en el header x-session-token cuando llame a endpoints protegidos.
const token = crypto.randomUUID();

return [{
  json: {
    success: true,
    token,
    user: {
      id:       user.id,
      username: user.username,
      nombre:   user.nombre || user.username,
      email:    user.email || '',
      rol:      user.rol || 'user',
      permisos: permisos
    },
    // Este objeto NO se devuelve al cliente; se usa sólo en el siguiente
    // nodo para actualizar last_login_at.
    _internal: { userId: user.id }
  }
}];

// Limpia _internal antes de devolver al cliente
const j = $('Verificar password').first().json;
return [{ json: { success: j.success, token: j.token, user: j.user } }];

// Saneo y sin exponer password_hash jamás.
function parseJsonField(v, fb) {
  if (v == null) return fb;
  if (Array.isArray(v) || typeof v === 'object') return v;
  if (typeof v === 'string') { try { return JSON.parse(v); } catch (_) { return fb; } }
  return fb;
}
const rows = $input.all().map(i => i.json).filter(u => u && u.id);
const usuarios = rows.map(u => ({
  id: u.id,
  username: u.username,
  nombre: u.nombre || '',
  email: u.email || '',
  rol: u.rol,
  permisos: parseJsonField(u.permisos, []),
  activo: !!u.activo,
  last_login_at: u.last_login_at,
  created_at: u.created_at,
  updated_at: u.updated_at
}));
return [{ json: { usuarios } }];

// Router CRUD para usuarios. El frontend envía:
//   { action: 'create' | 'update' | 'delete' | 'password', usuario: {...} }
// Hashea contraseñas con PBKDF2 antes de persistirlas.
const crypto = require('crypto');

function hashPassword(pw) {
  const salt = crypto.randomBytes(16);
  const iterations = 100000;
  const hash = crypto.pbkdf2Sync(pw, salt, iterations, 32, 'sha256');
  return `pbkdf2$${iterations}$${salt.toString('base64')}$${hash.toString('base64')}`;
}

const body = ($input.first().json.body) || {};
const action = String(body.action || '').toLowerCase();
const u = body.usuario || {};

if (!['create','update','delete','password'].includes(action)) {
  throw new Error('action requerida: create | update | delete | password');
}

const PERMISOS_VALIDOS = new Set(['ventas','distribucion','lista','bajas','sinasignar','proyectos','contabilidad','integraciones','admin','docs']);
function validarPermisos(arr) {
  const a = Array.isArray(arr) ? arr : [];
  return a.filter(p => PERMISOS_VALIDOS.has(String(p)));
}

let payload = null;

if (action === 'create') {
  if (!u.username || !u.password) throw new Error('username y password son obligatorios');
  payload = {
    username: String(u.username).trim().toLowerCase(),
    password_hash: hashPassword(String(u.password)),
    nombre: u.nombre ? String(u.nombre).trim() : null,
    email: u.email ? String(u.email).trim().toLowerCase() : null,
    rol: u.rol === 'admin' ? 'admin' : 'user',
    permisos: JSON.stringify(validarPermisos(u.permisos)),
    activo: u.activo !== false
  };
} else if (action === 'update') {
  if (!u.id) throw new Error('Falta id para update');
  payload = { id: u.id };
  if (u.nombre !== undefined)   payload.nombre   = u.nombre ? String(u.nombre).trim() : null;
  if (u.email  !== undefined)   payload.email    = u.email  ? String(u.email).trim().toLowerCase() : null;
  if (u.rol    !== undefined)   payload.rol      = u.rol === 'admin' ? 'admin' : 'user';
  if (u.permisos !== undefined) payload.permisos = JSON.stringify(validarPermisos(u.permisos));
  if (u.activo !== undefined)   payload.activo   = !!u.activo;
} else if (action === 'password') {
  if (!u.id || !u.password) throw new Error('Falta id o password para cambio de password');
  payload = { id: u.id, password_hash: hashPassword(String(u.password)) };
} else if (action === 'delete') {
  if (!u.id) throw new Error('Falta id para delete');
  payload = { id: u.id, deleted_at: new Date().toISOString(), activo: false };
}

return [{ json: { action, payload } }];

// Aplana: el item que llega a la HTTP Request debe ser DIRECTAMENTE el
// payload (id + columnas a actualizar), no {action, payload}.
return [{ json: $input.first().json.payload }];

// Construye respuesta consistente {success, action, affected, errores, usuario}
// sin exponer nunca password_hash.
const { action } = $('Preparar acción Usuario').first().json;
const input = $input.all();
let count = 0;
const errores = [];
let usuario = null;

for (const it of (input || [])) {
  const j = (it && it.json) ? it.json : it;
  if (!j) continue;
  if (j.error) {
    errores.push(String(j.error.message || j.error.code || j.error));
    continue;
  }
  if (j.code && j.message && !j.id) {
    errores.push(j.message + (j.details ? ' (' + j.details + ')' : ''));
    continue;
  }
  if (Array.isArray(j)) {
    count += j.length;
    if (!usuario && j.length > 0) usuario = j[0];
    continue;
  }
  if (j.id) { count++; if (!usuario) usuario = j; continue; }
}
if (usuario) delete usuario.password_hash;
return [{ json: { success: count > 0, action, affected: count, errores, usuario } }];
